-- SafetyNOTE 위험성평가 완전 복원 v3
-- 생성일: 2026-07-04
-- v2와의 차이:
--   ① work_categories INSERT OR REPLACE에 code 컬럼 포함 (NOT NULL 에러 수정)
--   ② work_categories 이름을 NAS 원본(0003 마이그레이션)에 맞게 수정
--   ③ work_types UPSERT 방식 변경: 먼저 DELETE 후 INSERT (category_id 정상화 보장)
--   ④ items는 work_types code 기반으로 재연결 (id 의존 제거)
--
-- 실행 방법 (NAS SSH):
--   sqlite3 /volume1/safetynote/data/safety.db < restore_items_v3.sql
--
-- ⚠️ 주의: 기존 work_types id 17~34 및 items를 완전 교체합니다.
--   실행 전 백업: sqlite3 /volume1/safetynote/data/safety.db ".backup /tmp/safety_backup.db"

BEGIN TRANSACTION;

-- ═══════════════════════════════════════════════════════════════
-- STEP 0: 기존 위험성평가 항목 정리 (중복/고아 제거)
-- ═══════════════════════════════════════════════════════════════
-- work_type_id 17 이상인 work_types 전부 삭제 후 재삽입
-- (이름·category_id 정합성 보장을 위해)
DELETE FROM risk_assessment_items WHERE work_type_id IN (
  SELECT id FROM work_types WHERE id >= 17
);
DELETE FROM work_types WHERE id >= 17;

-- ═══════════════════════════════════════════════════════════════
-- STEP 1: work_categories — id 지정 없이 code 기반 UPSERT
--   NAS 원본 이름(0003 마이그레이션)과 일치시킴
-- ═══════════════════════════════════════════════════════════════
