-- ═══════════════════════════════════════════════════════════════
-- STEP 4: 완료 확인
-- ═══════════════════════════════════════════════════════════════
COMMIT;

SELECT '=== 복원 결과 ===' as info;
SELECT 'work_categories' as tbl, COUNT(*) as cnt FROM work_categories
UNION ALL SELECT 'work_types', COUNT(*) FROM work_types
UNION ALL SELECT 'risk_assessment_items (전체)', COUNT(*) FROM risk_assessment_items
UNION ALL SELECT 'risk_assessment_items (활성)', COUNT(*) FROM risk_assessment_items WHERE COALESCE(is_active,1)=1;

SELECT '=== work_type별 항목 수 (코드 기준) ===' as info;
SELECT wt.code, wt.name, wc.name as cat, COUNT(rai.id) as cnt
FROM work_types wt
LEFT JOIN work_categories wc ON wc.id = wt.category_id
LEFT JOIN risk_assessment_items rai ON rai.work_type_id = wt.id
WHERE wt.code IN ('PIPE-EXCA','PIPE-INNER','PIPE-MANHOLE','PIPE-PRESS',
                  'EXTRA-HEAVY','DOC-PERMIT','LINE-FIBER','LINE-COAX',
                  'LINE-BOX','LINE-POLE','MAT-INOUT','TRANS-FIBER',
                  'TRANS-DATA','TRANS-MUX','POWER-PANEL','POWER-CABLE',
                  'INSP-FINAL','INSP-SITE')
GROUP BY wt.id ORDER BY wt.id;

SELECT '=== 고아 항목 확인 (0건이어야 정상) ===' as info;
SELECT rai.work_type_id, COUNT(*) as orphan_cnt
FROM risk_assessment_items rai
LEFT JOIN work_types wt ON wt.id = rai.work_type_id
WHERE wt.id IS NULL
GROUP BY rai.work_type_id;
